        // ===== OUTER: HIGH revenue branch =====
        HighRevenue(Double) from Fetcher to TaxSpecialist;
        HighNotice() from Fetcher to RevenueAnalyst;
        HighNotice() from Fetcher to TaxVerifier;
        HighNotice() from Fetcher to Writer;

